class Solution:
    def multiply(self, num1, num2):
        if num1 == '0' or num2 == '0':
            return '0'
        m, n = len(num1), len(num2)
        res = [0] * (m + n)
        for i in range(m - 1, -1, -1):
            d1 = ord(num1[i]) - 48
            for j in range(n - 1, -1, -1):
                d2 = ord(num2[j]) - 48
                s = res[i + j + 1] + d1 * d2
                res[i + j + 1] = s % 10
                res[i + j] += s // 10
        k = 0
        while k < len(res) - 1 and res[k] == 0:
            k += 1
        return ''.join(str(d) for d in res[k:])

